    <header class="main-header" :class="{ scrolled: isScrolled }">
      <div class="header-inner app-page">
        <div class="logo-section">
          <div class="logo">
            <span class="logo-icon">莆</span>
            <span class="logo-text">莆田文旅</span>
          </div>
          <div class="logo-subtitle">发现莆田之美</div>
        </div>

        <nav class="main-nav">
          <a
            v-for="item in navItems"
            :key="item.key"
            :class="['nav-item', { active: activeMenu === item.key }]"
            @click="handleMenuSelect(item.key)"
          >
            <el-icon class="nav-icon">
              <component :is="item.icon" />
            </el-icon>
            <span class="nav-text">{{ item.label }}</span>
          </a>
        </nav>

        <div class="header-actions">
          <div class="search-box">
            <input
              v-model="searchKeyword"
              type="text"
              placeholder="搜索景点、美食、酒店、攻略"
              class="search-input"
              @keyup.enter="handleSearch"
            />
            <button class="search-btn" @click="handleSearch">
              <el-icon><Search /></el-icon>
            </button>
          </div>

          <button class="announcement-btn" title="公告" @click="handleOpenAnnouncementDialog">
            <el-badge :is-dot="publishedAnnouncements.length > 0" class="announcement-badge">
              <el-icon><Bell /></el-icon>
            </el-badge>
          </button>

          <div class="user-section">
            <template v-if="isLogin">
              <el-dropdown @command="handleCommand">
                <div class="user-avatar-wrapper">
                  <el-avatar :src="userInfo.avatar || '/local-images/default-avatar.svg'" :size="36" />
                  <span class="user-name">{{ userInfo.nickName || userInfo.userName }}</span>
                  <el-icon class="arrow-down"><ArrowDown /></el-icon>
                </div>
                <template #dropdown>
                  <el-dropdown-menu class="user-dropdown">
                    <el-dropdown-item command="center">
                      <el-icon><User /></el-icon>
                      个人中心
                    </el-dropdown-item>
                    <el-dropdown-item command="publish">
                      <el-icon><Edit /></el-icon>
                      发布内容
                    </el-dropdown-item>
                    <el-dropdown-item command="admin" v-if="isAdminOrMerchant" divided>
                      <el-icon><Setting /></el-icon>
                      {{ isMerchant ? '商家中心' : '管理后台' }}
                    </el-dropdown-item>
                    <el-dropdown-item command="logout" divided>
                      <el-icon><SwitchButton /></el-icon>
                      退出登录
                    </el-dropdown-item>
                  </el-dropdown-menu>
                </template>
              </el-dropdown>
            </template>
            <template v-else>
              <el-button type="primary" class="login-btn" @click="goLogin">登录</el-button>
            </template>
          </div>
        </div>
      </div>
