        <div v-loading="loading" class="content-grid">
          <div
            v-for="(item, index) in contentList"
            :key="`${item.id}-${item.dataType}`"
            class="content-card"
            :style="{ animationDelay: `${index * 0.05}s` }"
            @click="goDetail(item)"
          >
            <div class="card-image-wrapper">
              <el-image
                :src="getHomeCover(item)"
                fit="cover"
                class="card-image"
                loading="lazy"
              >
                <template #error>
                  <div class="image-error">
                    <el-icon><Picture /></el-icon>
                  </div>
                </template>
              </el-image>
              <div class="card-badges">
                <span v-if="item.dataType === 3" class="type-tag video">
                  <el-icon><VideoPlay /></el-icon>
                </span>
                <span :class="['type-tag', `type-${item.dataType}`]">
                  {{ getTypeName(item.dataType) }}
                </span>
              </div>
              <div class="card-overlay">
                <button class="preview-btn" @click.stop="goDetail(item)">
                  <el-icon><ZoomIn /></el-icon>
                  查看详情
                </button>
                <button class="dislike-btn" @click.stop="dislikeContent(item)">
                  <el-icon><Close /></el-icon>
                  不感兴趣
                </button>
              </div>
            </div>
            <div class="card-body">
              <h3 class="card-title">{{ item.title }}</h3>
              <p class="card-desc">{{ item.description }}</p>
              <div v-if="item.recommendReason" class="recommend-reason">
                <span class="reason-label">推荐理由</span>
                <span class="reason-text">{{ item.recommendReason }}</span>
              </div>
              <div class="card-meta">
                <div class="meta-left">
                  <template v-if="item.authorName">
                    <el-avatar :src="item.authorAvatar" :size="20" />
                    <span class="author-name">{{ item.authorName }}</span>
                  </template>
                  <template v-else-if="item.region">
                    <el-icon class="meta-icon"><Location /></el-icon>
                    <span>{{ item.region }}</span>
                  </template>
                </div>
                <div class="meta-right">
                  <span class="meta-item">
                    <el-icon><View /></el-icon>
                    {{ item.viewCount || 0 }}
                  </span>
                  <span v-if="item.rating" class="meta-item rating">
                    <el-icon><Star /></el-icon>
                    {{ item.rating }}
                  </span>
                  <span v-if="item.likeCount !== undefined && item.likeCount !== null" class="meta-item">
                    <el-icon><Star /></el-icon>
                    {{ item.likeCount || 0 }}
                  </span>
                  <span v-if="item.collectCount !== undefined && item.collectCount !== null" class="meta-item">
                    <el-icon><Collection /></el-icon>
                    {{ item.collectCount || 0 }}
                  </span>
                </div>
              </div>
            </div>
