<script setup lang="ts">
  import { ref, computed, nextTick, onMounted, onUnmounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ElMessage } from 'element-plus'
import {
  Search,
  User,
  Edit,
  Setting,
  SwitchButton,
  ArrowDown,
  Location,
  View,
  Star,
  Collection,
  VideoPlay,
  ZoomIn,
  Picture,
  MapLocation,
  ForkSpoon,
  House,
  Guide,
  Compass,
  Position,
  Bell,
  Close
} from '@element-plus/icons-vue'
import request from '@/util/request'
import { formatDateTime } from '@/util/datetime'
import { getFirstImageUrl } from '@/utils/imageUrl'

const router = useRouter()
const route = useRoute()

const getHomeCover = (item: any) => getFirstImageUrl(item?.coverImage, item?.image, item?.images)

const isScrolled = ref(false)
const handleScroll = () => {
  isScrolled.value = window.scrollY > 80
}

const activeMenu = ref('home')
const searchKeyword = ref('')
const searchType = ref('attraction')
const isSearching = ref(false)
const isLogin = ref(false)
const userInfo = ref<any>({})
const loading = ref(false)
const contentList = ref<any[]>([])
const currentPage = ref(1)
const pageSize = ref(16)
const total = ref(0)
const featuredSectionRef = ref<HTMLElement | null>(null)
let contentRequestSeq = 0

interface Announcement {
  id: number
  title: string
  content: string
  type: number
  priority: number
  publishTime?: string | number[] | null
}

const announcementDialogVisible = ref(false)
const announcementLoading = ref(false)
const publishedAnnouncements = ref<Announcement[]>([])

const normalizeAnnouncementTime = (value?: string | number[] | null) => {
  if (Array.isArray(value)) {
    const [year, month, day, hour = 0, minute = 0, second = 0] = value
    return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')} ${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}:${String(second).padStart(2, '0')}`
  }
  return value || ''
}

const getAnnouncementTimeValue = (announcement: Announcement) => {
  const normalizedTime = normalizeAnnouncementTime(announcement.publishTime)
  const timeValue = normalizedTime ? new Date(normalizedTime.replace(/-/g, '/')).getTime() : 0
  return Number.isNaN(timeValue) ? 0 : timeValue
}

const getAnnouncementTypeName = (type?: number) => {
  const typeMap: Record<number, string> = {
    1: '系统维护',
    2: '平台活动',
    3: '政策提醒',
    4: '其他'
  }
  return typeMap[type || 4] || '其他'
}

const getAnnouncementTagType = (type?: number) => {
  const tagMap: Record<number, 'primary' | 'success' | 'warning' | 'info'> = {
    1: 'info',
    2: 'success',
    3: 'warning',
    4: 'primary'
  }
  return tagMap[type || 4] || 'primary'
}

const loadPublishedAnnouncements = async () => {
  announcementLoading.value = true
  try {
    const res: any = await request.get('/announcement/published', {
      params: {
        pageNum: 1,
        pageSize: 20
      }
    })
    const list = res?.data?.list || res?.data?.records || []
    publishedAnnouncements.value = [...list].sort((a, b) => getAnnouncementTimeValue(b) - getAnnouncementTimeValue(a))
  } catch (error) {
    console.warn('加载公告失败:', error)
  } finally {
    announcementLoading.value = false
  }
}

const handleOpenAnnouncementDialog = async () => {
  announcementDialogVisible.value = true
  await loadPublishedAnnouncements()
}

const menuTypeMap: Record<string, number | null> = {
  home: null,
  attraction: 2,
  food: 3,
  hotel: 4,
