const currentCategoryTitle = computed(() => {
  if (activeMenu.value === 'home') return '精选推荐'
  const map: Record<string, string> = {
    attraction: '景点精选',
    food: '美食精选',
    hotel: '酒店精选',
    guide: '攻略精选'
  }
  return map[activeMenu.value] || '精选推荐'
})

const currentSectionTitle = computed(() => {
  if (!isSearching.value) {
    return homeFeedOptions.find(item => item.value === homeFeedMode.value)?.label || '为你推荐'
  }
  return currentCategoryTitle.value
})

const currentSectionSubtitle = computed(() => {
  if (!isSearching.value) {
    const subtitleMap: Record<HomeFeedMode, string> = {
      recommend: isLogin.value
        ? '结合浏览、点赞、收藏与搜索行为，动态推荐更贴合你的莆田内容'
