const getUserInfo = async () => {
  try {
    const res: any = await request.get('/user/info')
    if (res.code === 200) {
      userInfo.value = res.data
      localStorage.setItem('userInfo', JSON.stringify(res.data))
    }
  } catch (error) {
    console.error('获取用户信息失败', error)
  }
