const loadContents = async () => {
  const requestSeq = ++contentRequestSeq
  loading.value = true
  try {
    await loadFeedContents(requestSeq)
  } catch (error) {
    ElMessage.error('加载内容失败')
    console.error(error)
  } finally {
    if (requestSeq === contentRequestSeq) {
      loading.value = false
    }
  }
}

const loadFeedContents = async (requestSeq = contentRequestSeq) => {
  const keyword = searchKeyword.value.trim()
  const params: any = {
    pageNum: currentPage.value,
    pageSize: pageSize.value,
    dataType: filterDataType.value ?? undefined
  }

  if (filterRegion.value && filterRegion.value !== '全部') {
    params.region = filterRegion.value
  }

  if (isSearching.value && keyword) {
    params.title = keyword
  }

  if (homeFeedMode.value === 'hot') {
    params.sortType = 2
  } else if (homeFeedMode.value === 'latest') {
    params.sortType = 1
  } else {
    params.sortType = filterSort.value
  }

  const requestUrl = homeFeedMode.value === 'recommend' && filterSort.value === 0 && !(isSearching.value && keyword)
    ? '/content/recommend/home'
    : '/content/search'
  const recommendRes: any = await request.get(requestUrl, { params })
  if (requestSeq !== contentRequestSeq) return

  if (recommendRes.code === 200) {
    let list = recommendRes.data.list || recommendRes.data.records || []
    const seen = new Set<string>()
    list = list.filter((item: any) => {
      const key = `${item.id}-${item.dataType}`
      if (seen.has(key)) {
        console.warn('检测到重复内容：', key)
        return false
      }
      seen.add(key)
      return true
    })
    contentList.value = list
    total.value = recommendRes.data.total || 0
  } else {
    contentList.value = []
    total.value = 0
  }
}

