const scrollToFeaturedSection = async () => {
  await nextTick()

  const section = featuredSectionRef.value
  if (!section) return

  const header = document.querySelector('.main-header') as HTMLElement | null
  const headerHeight = header?.offsetHeight ?? 0
  const sectionTop = section.getBoundingClientRect().top + window.scrollY

  window.scrollTo({
    top: Math.max(sectionTop - headerHeight - 24, 0),
    behavior: 'smooth'
  })
}

const handleMenuSelect = (index: string) => {
  activeMenu.value = index
  isSearching.value = false
  searchKeyword.value = ''
  filterDataType.value = menuTypeMap[index]
  currentPage.value = 1

  router.replace({
    path: '/home',
    query: index === 'home' ? {} : { menu: index }
  })

  loadContents()
  scrollToFeaturedSection()
