const handleSearch = () => {
  if (searchKeyword.value.trim()) {
    isSearching.value = true
    currentPage.value = 1
    loadContents()
  }
}

const quickSearch = (tag: string) => {
  searchKeyword.value = tag
  handleSearch()
}

const navigateToCategory = (type: string | number) => {
  if (type === 'map') {
    router.push('/ai-map')
  } else if (type === 'route') {
    router.push('/route')
  } else {
    const targetMenu = Object.entries(menuTypeMap).find(([, value]) => value === type)?.[0] || 'home'
    handleMenuSelect(targetMenu)
  }
}

const applyHomeMenuFromRoute = (menu?: string) => {
  const targetMenu = menu && menuTypeMap[menu] !== undefined ? menu : 'home'
  activeMenu.value = targetMenu
  isSearching.value = false
  filterDataType.value = menuTypeMap[targetMenu]
  currentPage.value = 1
