const goDetail = (item: any) => {
  const routeMap: Record<number, string> = {
    1: `/content/${item.id}`,
    2: `/attraction/${item.id}`,
    3: `/food/${item.id}`,
    4: `/hotel/${item.id}`
  }
  router.push(routeMap[item.dataType] || '/')
}

const dislikeContent = async (item: any) => {
  if (!isLogin.value) {
    ElMessage.warning('登录后可以使用不感兴趣')
    router.push('/login')
    return
  }

  const previousList = [...contentList.value]
  const previousTotal = total.value
  const dislikeKey = `${item.id}-${item.dataType}`

  contentList.value = contentList.value.filter(
    (content: any) => `${content.id}-${content.dataType}` !== dislikeKey
  )
  total.value = Math.max(0, total.value - 1)

  try {
    await request.post('/content/recommend/dislike', null, {
      params: {
        contentId: item.id,
        dataType: item.dataType,
        reason: '不感兴趣'
      }
    })
    ElMessage.success('已减少类似推荐')
  } catch (error) {
    contentList.value = previousList
    total.value = previousTotal
    console.error('设置不感兴趣失败', error)
  }
}

