.main-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  transition: all 0.3s ease;
  background: transparent;

  &.scrolled {
    background: rgba(255, 255, 255, 0.98);
    backdrop-filter: blur(20px);
    box-shadow: $shadow-sm;

    .logo-text,
    .nav-item,
    .search-btn,
    .announcement-btn {
      color: $text-primary !important;
    }

    .logo-subtitle {
      color: $text-muted !important;
    }

    .search-box {
      background: $bg-light;
      border-color: $border;

      .search-input {
        color: $text-primary !important;

        &::placeholder {
          color: $text-muted;
        }
      }
    }

    .announcement-btn {
      background: $bg-light;
      border-color: $border;

      &:hover {
        background: rgba(26, 95, 74, 0.08);
      }
    }

    .nav-item::after {
      background: $primary;
    }

    .user-avatar-wrapper {
      .user-name {
        color: $text-primary !important;
      }

      .arrow-down {
        color: $text-secondary !important;
      }

      &:hover {
        background: $bg-light;
      }
    }

    .login-btn {
      background: $accent;
      border: none;
      color: $white !important;

      &:hover {
        background: $accent-light;
      }
    }

    .logo-section .logo .logo-icon {
      filter: none;
    }
  }

  .header-inner {
    max-width: 1400px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 28px;
    padding: 16px 40px;
  }

  .logo-section {
    flex: 0 0 auto;

    .logo {
      display: flex;
      align-items: center;
      gap: 10px;
      cursor: pointer;

      .logo-icon {
        font-size: 32px;
      }

      .logo-text {
        font-size: 24px;
        font-weight: 700;
        color: $white;
        transition: color 0.3s;
      }
    }

    .logo-subtitle {
      font-size: 12px;
      color: rgba(255, 255, 255, 0.8);
      margin-top: 2px;
      transition: color 0.3s;
    }
  }

  .main-nav {
    flex: 0 0 auto;
    display: flex;
    gap: 8px;

    .nav-item {
      position: relative;
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 10px 20px;
      color: rgba(255, 255, 255, 0.9);
      font-size: 15px;
      white-space: nowrap;
      cursor: pointer;
      transition: color 0.3s;
      border-radius: 8px;

      &:hover,
      &.active {
        color: $white;
        background: rgba(255, 255, 255, 0.1);
      }

      &.active::after {
        content: '';
        position: absolute;
        bottom: 0;
        left: 50%;
        transform: translateX(-50%);
        width: 24px;
        height: 3px;
        background: $accent;
        border-radius: 2px;
      }

      .nav-icon {
        flex: 0 0 auto;
        font-size: 17px;
      }
    }
  }

  .header-actions {
    flex: 1 1 280px;
    min-width: 0;
    display: flex;
    align-items: center;
    gap: 20px;

    .search-box {
      flex: 1 1 260px;
      min-width: 180px;
      max-width: 360px;
      display: flex;
      align-items: center;
      background: rgba(255, 255, 255, 0.15);
      border: 1px solid rgba(255, 255, 255, 0.2);
      border-radius: 30px;
      padding: 0 16px;
      transition: all 0.3s;

      &:focus-within {
        background: $white;
        border-color: $primary;
        box-shadow: 0 0 0 3px rgba(26, 95, 74, 0.1);
      }

      .search-input {
        flex: 1 1 auto;
        min-width: 0;
        border: none;
        background: transparent;
        padding: 8px 12px;
        font-size: 14px;
        outline: none;

        &::placeholder {
          color: rgba(255, 255, 255, 0.6);
        }
      }

      .search-btn {
        border: none;
        background: transparent;
        color: $white;
        cursor: pointer;
        padding: 4px;
        transition: color 0.3s;

        &:hover {
          color: $primary;
        }
      }

      &:focus-within .search-btn {
        color: $primary;
      }

      &:focus-within .search-input::placeholder {
        color: $text-muted;
      }
    }

    .announcement-btn {
      flex: 0 0 auto;
      width: 42px;
      height: 42px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      border: 1px solid rgba(255, 255, 255, 0.22);
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.14);
      color: $white;
      cursor: pointer;
      transition: all 0.3s ease;
      backdrop-filter: blur(10px);

      .el-icon {
        font-size: 20px;
      }

      &:hover {
        background: rgba(255, 255, 255, 0.24);
        transform: translateY(-1px);
      }

      :deep(.el-badge__content.is-fixed.is-dot) {
        right: 4px;
        top: 4px;
        background: $accent;
      }
    }

    .user-section {
      .user-avatar-wrapper {
        display: flex;
        align-items: center;
        gap: 8px;
        cursor: pointer;
        padding: 4px 12px 4px 4px;
        border-radius: 24px;
        transition: background 0.3s;

        &:hover {
          background: rgba(255, 255, 255, 0.1);
        }

        .user-name {
          color: $white;
          font-size: 14px;
        }

        .arrow-down {
          color: rgba(255, 255, 255, 0.6);
          font-size: 12px;
        }
      }

      .login-btn {
        background: $accent;
        border: none;
        border-radius: 20px;
        padding: 8px 24px;
        font-weight: 500;

        &:hover {
          background: $accent-light;
        }
      }
    }
  }
}

:deep(.user-dropdown) {
  border-radius: 12px;
  padding: 8px;
  box-shadow: $shadow-md;

  .el-dropdown-menu__item {
    border-radius: 8px;
    padding: 10px 16px;
    display: flex;
    align-items: center;
    gap: 8px;

    .el-icon {
      font-size: 16px;
      color: $text-secondary;
    }
  }
}

