.hero-section {
  position: relative;
  min-height: 580px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 120px 40px 60px;
  overflow: hidden;

  .hero-background {
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, #0f3d2f 0%, #1a5f4a 50%, #2d8b6f 100%);

    .hero-overlay {
      position: absolute;
      inset: 0;
      background: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><defs><pattern id="grain" width="100" height="100" patternUnits="userSpaceOnUse"><circle cx="25" cy="25" r="1" fill="rgba(255,255,255,0.05)"/><circle cx="75" cy="75" r="1" fill="rgba(255,255,255,0.03)"/><circle cx="50" cy="10" r="0.5" fill="rgba(255,255,255,0.08)"/></pattern></defs><rect width="100" height="100" fill="url(%23grain)"/></svg>');
    }

    .hero-pattern {
      position: absolute;
      inset: 0;
      background:
        radial-gradient(ellipse at 20% 80%, rgba(232, 168, 56, 0.15) 0%, transparent 50%),
        radial-gradient(ellipse at 80% 20%, rgba(45, 139, 111, 0.2) 0%, transparent 50%);
    }
  }

  .hero-content {
    position: relative;
    z-index: 1;
    text-align: center;
    max-width: 800px;
  }

  .hero-title {
    margin: 0 0 20px;
    display: flex;
    flex-direction: column;
    gap: 8px;

    .title-line {
      font-size: 48px;
      font-weight: 700;
      color: $white;
      letter-spacing: 8px;
      text-shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
    }

    .title-highlight {
      font-size: 72px;
      font-weight: 800;
      color: $accent;
      letter-spacing: 12px;
      text-shadow: 0 4px 30px rgba(232, 168, 56, 0.4);
      animation: titleFloat 3s ease-in-out infinite;
    }
  }

  .hero-subtitle {
    font-size: 18px;
    color: rgba(255, 255, 255, 0.8);
    margin: 0 0 40px;
    letter-spacing: 2px;
  }

  .hero-search {
    background: $white;
    border-radius: 16px;
    padding: 20px;
    box-shadow: $shadow-lg;

    .search-tabs {
      display: flex;
      gap: 8px;
      margin-bottom: 16px;
      padding-bottom: 16px;
      border-bottom: 1px solid $border;

      .search-tab {
        display: flex;
        align-items: center;
        gap: 8px;
        padding: 10px 20px;
        border: none;
        background: $bg-light;
        border-radius: 24px;
        cursor: pointer;
        transition: all 0.3s;
        font-size: 14px;
        color: $text-secondary;

        &:hover {
          background: rgba(26, 95, 74, 0.1);
        }

        &.active {
          background: $primary;
          color: $white;
        }
      }
    }

    .search-form {
      display: flex;
      gap: 12px;

      .main-search-input {
        flex: 1;
        border: 2px solid $border;
        border-radius: 12px;
        padding: 16px 20px;
        font-size: 15px;
        outline: none;
        transition: all 0.3s;

        &:focus {
          border-color: $primary;
          box-shadow: 0 0 0 4px rgba(26, 95, 74, 0.1);
        }
      }

      .search-button {
        background: linear-gradient(135deg, $primary, $primary-light);
        border: none;
        border-radius: 12px;
        padding: 16px 32px;
        color: $white;
        font-size: 15px;
        font-weight: 600;
        cursor: pointer;
        display: flex;
        align-items: center;
        gap: 8px;
        transition: all 0.3s;

        &:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 24px rgba(26, 95, 74, 0.3);
        }
      }
    }

    .search-tags {
      display: flex;
      align-items: center;
      gap: 8px;
      margin-top: 16px;
      justify-content: center;

      .tag-label {
        font-size: 13px;
        color: $text-muted;
      }

      .hot-tag {
        padding: 4px 12px;
        background: rgba(232, 168, 56, 0.1);
        color: $accent;
        border-radius: 12px;
        font-size: 13px;
        cursor: pointer;
        transition: all 0.3s;

        &:hover {
          background: $accent;
          color: $white;
        }
      }
    }
  }

  .quick-entry {
    position: absolute;
    bottom: -40px;
    display: flex;
    gap: 24px;
    background: $white;
    padding: 20px 40px;
    border-radius: 16px;
    box-shadow: $shadow-md;
    z-index: 2;

    .entry-item {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 8px;
      cursor: pointer;
      transition: all 0.3s;

      .entry-icon {
        width: 56px;
        height: 56px;
        background: linear-gradient(135deg, $bg-light, #e8f0ec);
        border-radius: 14px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 26px;
        transition: all 0.3s;
      }

      .entry-label {
        font-size: 13px;
        color: $text-secondary;
        font-weight: 500;
      }

      &:hover {
        transform: translateY(-4px);

        .entry-icon {
          background: linear-gradient(135deg, $primary, $primary-light);
          box-shadow: 0 8px 20px rgba(26, 95, 74, 0.3);
        }

        .entry-label {
          color: $primary;
        }
      }
    }
  }
}

@keyframes titleFloat {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-8px);
  }
}

