.main-content {
  max-width: 1400px;
  margin: 0 auto;
  padding: 80px 40px 60px;
}

.featured-section {
  .section-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    margin-bottom: 24px;

    .section-title-group {
      .section-title {
        margin: 0;
        font-size: 28px;
        font-weight: 700;
        color: $text-primary;
        display: flex;
        align-items: center;
        gap: 12px;

        &::before {
          content: '';
          width: 5px;
          height: 28px;
          background: linear-gradient(180deg, $primary, $primary-light);
          border-radius: 3px;
        }
      }

      .section-subtitle {
        margin: 8px 0 0;
        font-size: 14px;
        color: $text-muted;
      }
    }

    .section-actions {
      display: flex;
      gap: 8px;

      .sort-btn {
        border-radius: 20px;
        padding: 8px 20px;
        border-color: $border;
        color: $text-secondary;

        &.active {
          background: $primary;
          border-color: $primary;
          color: $white;
        }
      }
    }
  }


  .filter-bar {
    background: $white;
    border-radius: 12px;
    padding: 20px 24px;
    margin-bottom: 24px;
    box-shadow: $shadow-sm;

    .filter-group {
      display: flex;
      align-items: center;
      margin-bottom: 12px;

      &:last-child {
        margin-bottom: 0;
      }

      .filter-label {
        min-width: 50px;
        font-size: 14px;
        color: $text-secondary;
        font-weight: 500;
      }

      .filter-pills {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;

        .filter-pill {
          padding: 6px 16px;
          background: $bg-light;
          color: $text-secondary;
          border-radius: 16px;
          font-size: 13px;
          cursor: pointer;
          transition: all 0.3s;

          &:hover {
            background: rgba(26, 95, 74, 0.1);
            color: $primary;
          }

          &.active {
            background: $primary;
            color: $white;
          }
        }
      }
    }
  }
}

