.content-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 24px;
  min-height: 400px;

  @media (max-width: 1200px) {
    grid-template-columns: repeat(3, 1fr);
  }

  @media (max-width: 900px) {
    grid-template-columns: repeat(2, 1fr);
  }

  .content-card {
    background: $white;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: $shadow-sm;
    cursor: pointer;
    transition: all 0.4s ease;
    animation: fadeInUp 0.5s ease-out both;

    &:hover {
      transform: translateY(-8px);
      box-shadow: $shadow-lg;

      .card-image-wrapper {
        .card-image {
          transform: scale(1.1);
        }

        .card-overlay {
          opacity: 1;
        }
      }

      .card-title {
        color: $primary;
      }
    }

    .card-image-wrapper {
      position: relative;
      height: 200px;
      overflow: hidden;

      .card-image {
        width: 100%;
        height: 100%;
        transition: transform 0.5s ease;
      }

      .image-error {
        width: 100%;
        height: 100%;
        display: flex;
        align-items: center;
        justify-content: center;
        background: $bg-light;
        color: $text-muted;
        font-size: 40px;
      }

      .card-badges {
        position: absolute;
        top: 12px;
        left: 12px;
        display: flex;
        gap: 8px;

        .type-tag {
          padding: 4px 10px;
          border-radius: 6px;
          font-size: 12px;
          font-weight: 600;
          color: $white;

          &.type-1 { background: linear-gradient(135deg, #667eea, #764ba2); }
          &.type-2 { background: linear-gradient(135deg, $primary, $primary-light); }
          &.type-3 { background: linear-gradient(135deg, #f093fb, #f5576c); }
          &.type-4 { background: linear-gradient(135deg, #4facfe, #00f2fe); }
          &.video {
            background: rgba(0, 0, 0, 0.6);
            display: flex;
            align-items: center;
            justify-content: center;
            width: 28px;
            height: 28px;
            padding: 0;
          }
        }
      }

      .card-overlay {
        position: absolute;
        inset: 0;
        background: rgba(0, 0, 0, 0.4);
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        gap: 10px;
        opacity: 0;
        transition: opacity 0.3s;

        .preview-btn,
        .dislike-btn {
          background: $white;
          border: none;
          border-radius: 24px;
          padding: 10px 24px;
          color: $text-primary;
          font-size: 14px;
          cursor: pointer;
          display: flex;
          align-items: center;
          gap: 6px;
          transition: all 0.3s;
        }

        .preview-btn {
          &:hover {
            background: $primary;
            color: $white;
          }
        }

        .dislike-btn {
          background: rgba(255, 255, 255, 0.92);
          color: #5d4b3c;

          &:hover {
            background: #8b3a2f;
            color: $white;
          }
        }
      }
    }

    .card-body {
      padding: 16px;

      .card-title {
        margin: 0 0 8px;
        font-size: 16px;
        font-weight: 600;
        color: $text-primary;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
        transition: color 0.3s;
      }

      .card-desc {
        margin: 0 0 12px;
        font-size: 13px;
        color: $text-muted;
        line-height: 1.6;
        height: 40px;
        overflow: hidden;
        display: -webkit-box;
        -webkit-line-clamp: 2;
        -webkit-box-orient: vertical;
      }

      .recommend-reason {
        display: flex;
        align-items: flex-start;
        gap: 6px;
        min-height: 28px;
        margin: -2px 0 12px;
        padding: 7px 9px;
        border: 1px solid #e1ebe4;
        border-radius: 8px;
        background: #f3f7f4;
        color: #355f50;
        font-size: 12px;
        line-height: 1.4;

        .reason-label {
          flex: 0 0 auto;
          font-weight: 700;
          color: #1f513f;
        }

        .reason-text {
          min-width: 0;
          overflow: hidden;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
        }
      }

      .card-meta {
        display: flex;
        justify-content: space-between;
        align-items: center;

        .meta-left {
          display: flex;
          align-items: center;
          gap: 8px;
          font-size: 12px;
          color: $text-muted;

          .meta-icon {
            color: $primary-light;
          }

          .author-name {
            max-width: 80px;
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
        }

        .meta-right {
          display: flex;
          align-items: center;
          gap: 12px;

          .meta-item {
            display: flex;
            align-items: center;
            gap: 4px;
            font-size: 12px;
            color: $text-muted;

            .el-icon {
              font-size: 14px;
            }

            &.rating {
              color: $accent;
            }
          }
        }
      }
    }
  }
}

.discovery-section {
  margin-top: 36px;

  &.latest {
    margin-top: 28px;
    margin-bottom: 32px;
  }
}

.subsection-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  margin-bottom: 18px;
}

.subsection-title {
  margin: 0;
  font-size: 22px;
  color: $text-primary;
  font-weight: 700;
}

.subsection-subtitle {
  margin: 6px 0 0;
  font-size: 13px;
  color: $text-muted;
}

.subsection-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
}

.subsection-card {
  overflow: hidden;
  background: $white;
  border-radius: 16px;
  box-shadow: $shadow-sm;
  cursor: pointer;
  transition: transform 0.25s ease, box-shadow 0.25s ease;

  &:hover {
    transform: translateY(-4px);
    box-shadow: $shadow-md;
  }
}

.subsection-image {
  width: 100%;
  height: 188px;
  display: block;
}

.subsection-body {
  padding: 16px;
}

.subsection-badges {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 10px;
}

.mini-tag {
  display: inline-flex;
  align-items: center;
  height: 28px;
  padding: 0 10px;
  border-radius: 999px;
  background: rgba(26, 95, 74, 0.1);
  color: $primary;
  font-size: 12px;
  font-weight: 600;

  &.ghost {
    background: rgba(0, 0, 0, 0.04);
    color: $text-secondary;
  }
}

.subsection-card-title {
  margin: 0;
  font-size: 17px;
  font-weight: 700;
  color: $text-primary;
  line-height: 1.4;
}

.subsection-card-desc {
  margin: 8px 0 14px;
  font-size: 13px;
  color: $text-secondary;
  line-height: 1.7;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.subsection-meta {
  display: flex;
  gap: 16px;
  font-size: 12px;
  color: $text-muted;

  span {
    display: inline-flex;
    align-items: center;
    gap: 6px;
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.empty-state {
  padding: 60px 20px;

  .empty-illustration {
    font-size: 80px;
  }

  .empty-text {
    color: $text-muted;
    font-size: 15px;
  }
}

