.ai-float-button {
  position: fixed;
  bottom: 40px;
  right: 40px;
  z-index: 999;
  cursor: pointer;

  .ai-content {
    width: 70px;
    height: 70px;
    background: linear-gradient(135deg, $primary, $primary-light);
    border-radius: 50%;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    box-shadow: 0 8px 24px rgba(26, 95, 74, 0.4);
    transition: all 0.3s;
    position: relative;
    z-index: 1;

    .ai-icon {
      font-size: 24px;
    }

    .ai-label {
      font-size: 11px;
      color: $white;
      font-weight: 600;
    }
  }

  .ai-ripple {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    background: linear-gradient(135deg, $primary, $primary-light);
    animation: ripple 2s infinite;
  }

  &:hover .ai-content {
    transform: scale(1.1);
    box-shadow: 0 12px 32px rgba(26, 95, 74, 0.5);
  }
}

@keyframes ripple {
  0% {
    transform: scale(1);
    opacity: 0.5;
  }
  100% {
    transform: scale(1.5);
    opacity: 0;
  }
}

