.main-footer {
  background: linear-gradient(180deg, #1a1a1a 0%, #0a0a0a 100%);
  color: $white;
  margin-top: 80px;

  .footer-content {
    max-width: 1400px;
    margin: 0 auto;
    padding: 60px 40px;
    display: flex;
    justify-content: space-between;

    .footer-brand {
      .footer-logo {
        display: flex;
        align-items: center;
        gap: 10px;
        font-size: 24px;
        font-weight: 700;

        .logo-icon {
          font-size: 32px;
        }
      }

      .footer-desc {
        margin: 12px 0 0;
        color: rgba(255, 255, 255, 0.6);
        font-size: 14px;
      }
    }

    .footer-links {
      display: flex;
      gap: 80px;

      .link-group {
        h4 {
          margin: 0 0 16px;
          font-size: 16px;
          font-weight: 600;
        }

        a {
          display: block;
          color: rgba(255, 255, 255, 0.6);
          font-size: 14px;
          margin-bottom: 10px;
          text-decoration: none;
          transition: color 0.3s;

          &:hover {
            color: $accent;
          }
        }

        .social-icons {
          display: flex;
          gap: 12px;

          .social-icon {
            width: 36px;
            height: 36px;
            background: rgba(255, 255, 255, 0.1);
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s;

            &:hover {
              background: $primary;
              transform: translateY(-2px);
            }
          }
        }
      }
    }
  }

  .footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    padding: 20px;
    text-align: center;

    p {
      margin: 0;
      color: rgba(255, 255, 255, 0.4);
      font-size: 13px;
    }
  }
}

// Design refresh overrides
.home-container {
  position: relative;
  background:
    radial-gradient(circle at 0% 10%, rgba(214, 154, 45, 0.08), transparent 24%),
    radial-gradient(circle at 100% 0%, rgba(31, 111, 95, 0.12), transparent 28%);
}

.main-header {
  &.scrolled {
    box-shadow: 0 16px 34px rgba(18, 51, 45, 0.08);
  }

  .header-inner {
    min-height: 78px;
  }

  .logo-section {
    .logo {
      gap: 10px;
      font-weight: 800;
      letter-spacing: 1px;
    }

    .logo-icon {
      width: 42px;
      height: 42px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      border-radius: 14px;
      background: linear-gradient(135deg, rgba(214, 154, 45, 0.18), rgba(31, 111, 95, 0.12));
      box-shadow: inset 0 0 0 1px rgba(18, 51, 45, 0.08);
    }

    .logo-text {
      color: var(--app-ink);
    }

    .logo-subtitle {
      color: rgba(18, 51, 45, 0.58);
      letter-spacing: 2px;
      text-transform: uppercase;
    }
  }

  .main-nav .nav-item {
    position: relative;
    border-radius: 999px;
    backdrop-filter: blur(10px);

    &::after {
      content: '';
      position: absolute;
      left: 16px;
      right: 16px;
      bottom: 6px;
      height: 2px;
      border-radius: 999px;
      background: linear-gradient(90deg, transparent, $accent, transparent);
      opacity: 0;
      transition: opacity 0.25s ease;
    }

    &.active::after,
    &:hover::after {
      opacity: 1;
    }
  }

  .search-box,
  .announcement-btn,
  .user-avatar-wrapper {
    box-shadow: 0 12px 24px rgba(18, 51, 45, 0.08);
  }
}

.hero-section {
  min-height: 660px;
  padding: 132px 40px 88px;

  .hero-background {
    background:
      linear-gradient(135deg, rgba(7, 29, 24, 0.88) 0%, rgba(20, 74, 60, 0.82) 48%, rgba(40, 114, 93, 0.76) 100%),
      url('/local-images/home-hero-travel.jpg')
        center/cover;

    .hero-overlay {
      background:
        linear-gradient(180deg, rgba(8, 20, 18, 0.12), rgba(8, 20, 18, 0.24)),
        radial-gradient(circle at top left, rgba(214, 154, 45, 0.22), transparent 22%);
      mix-blend-mode: screen;
    }

    .hero-pattern {
      background:
        linear-gradient(135deg, rgba(255, 255, 255, 0.05) 0 1px, transparent 1px),
        linear-gradient(45deg, rgba(255, 255, 255, 0.03) 0 1px, transparent 1px);
      background-size: 28px 28px, 28px 28px;
      opacity: 0.38;
    }
  }

  .hero-content {
    max-width: 920px;
  }

  .hero-title {
    .title-line {
      font-size: 42px;
      letter-spacing: 10px;
    }

    .title-highlight {
      font-size: 88px;
      letter-spacing: 14px;
      color: #f3c86b;
      text-shadow:
        0 10px 36px rgba(214, 154, 45, 0.24),
        0 2px 0 rgba(255, 255, 255, 0.14);
    }
  }

  .hero-subtitle {
    max-width: 680px;
    margin: 0 auto 44px;
    font-size: 16px;
    line-height: 1.9;
    color: rgba(255, 255, 255, 0.78);
  }

  .hero-search {
    border-radius: 28px;
    padding: 24px;
    background: rgba(255, 250, 244, 0.92);
    border: 1px solid rgba(214, 154, 45, 0.2);
    box-shadow: 0 30px 70px rgba(8, 20, 18, 0.26);

    .search-tabs {
      border-bottom-color: rgba(18, 51, 45, 0.08);
    }

    .search-tab {
      border-radius: 999px;
      background: rgba(18, 51, 45, 0.04);
      font-weight: 600;
    }

    .search-form .main-search-input {
      border-radius: 18px;
      background: rgba(255, 255, 255, 0.84);
    }

    .search-form .search-button {
      border-radius: 18px;
      padding-inline: 36px;
      box-shadow: 0 16px 28px rgba(26, 95, 74, 0.2);
    }
  }

  .quick-entry {
    bottom: -52px;
    gap: 18px;
    padding: 16px 18px;
    border-radius: 22px;
    background: rgba(255, 252, 248, 0.92);
    border: 1px solid rgba(214, 154, 45, 0.16);
    box-shadow: 0 22px 46px rgba(18, 51, 45, 0.14);
  }
}

.featured-section {
  position: relative;

  .section-header {
    margin-bottom: 28px;
  }

  .section-title-group {
    .section-title {
      font-size: 32px;
      letter-spacing: 1px;
    }

    .section-subtitle {
      font-size: 15px;
      color: rgba(18, 51, 45, 0.62);
    }
  }

  .filter-bar {
    border-radius: 22px;
    border: 1px solid rgba(18, 51, 45, 0.08);
    background: rgba(255, 255, 255, 0.72);
    backdrop-filter: blur(14px);
    box-shadow: 0 18px 40px rgba(18, 51, 45, 0.08);
  }

  .filter-pill {
    border-radius: 999px !important;
  }
}

.content-grid {
  gap: 28px;

  .content-card {
    border-radius: 22px;
    border: 1px solid rgba(18, 51, 45, 0.08);
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.98), rgba(245, 249, 247, 0.98));
    box-shadow: 0 18px 42px rgba(18, 51, 45, 0.08);

    &:hover {
      transform: translateY(-10px) rotateX(1deg);
      box-shadow: 0 28px 56px rgba(18, 51, 45, 0.14);
    }

    .card-image-wrapper {
      height: 224px;

      &::after {
        content: '';
        position: absolute;
        inset: auto 0 0;
        height: 48%;
        background: linear-gradient(180deg, transparent, rgba(8, 20, 18, 0.36));
        pointer-events: none;
      }

      .card-badges .type-tag {
        border-radius: 999px;
        box-shadow: 0 8px 18px rgba(8, 20, 18, 0.16);
      }
    }

    .card-body {
      padding: 18px 18px 20px;

      .card-title {
        white-space: normal;
        line-height: 1.45;
        min-height: 46px;
      }

      .card-desc {
        height: 44px;
      }
    }
  }
}

.ai-float-button {
  .ai-content {
    width: 76px;
    height: 76px;
    background: linear-gradient(135deg, #163f35 0%, #2d8b6f 100%);
    border: 2px solid rgba(255, 255, 255, 0.22);
  }
}

.main-footer {
  position: relative;
  background:
    radial-gradient(circle at top left, rgba(214, 154, 45, 0.12), transparent 20%),
    linear-gradient(180deg, #101917 0%, #07110f 100%);

  .footer-content {
    position: relative;
    z-index: 1;
  }
